  1→import React, { useState, useEffect } from 'react';
  2→import { authenticatedGet, authenticatedPost, authenticatedPut, authenticatedDelete, getUser, hasVulnAccess } from '../utils/auth';
  3→import { isAdmin, isSecChampion } from '../utils/permissions';
  4→import PortHistory from './PortHistory';
  5→import VulnerabilityHistory from './VulnerabilityHistory';
  6→import { BulkDeleteConfirmModal } from './BulkDeleteConfirmModal';
  7→import { bulkDeleteAssets, type BulkDeleteResult } from '../services/assetService';
  8→import { exportVulnerabilitiesServerSide, cancelExportJob, type ExportJob } from '../services/vulnerabilityManagementService';
  9→
 10→interface WorkgroupSummary {
 11→  id: number;
 12→  name: string;
 13→}
 14→
 15→interface Workgroup {
 16→  id: number;
 17→  name: string;
 18→  description?: string;
 19→}
 20→
 21→interface OwnerCandidate {
 22→  value: string;
 23→  label: string;
 24→}
 25→
 26→interface Asset {
 27→  id?: number;
 28→  name: string;
 29→  type: string;
 30→  ip?: string;
 31→  owner: string;
 32→  description?: string;
 33→  groups?: string;
 34→  cloudAccountId?: string;
 35→  cloudInstanceId?: string;
 36→  osVersion?: string;
 37→  adDomain?: string;
 38→  criticality?: 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW' | 'NA' | null;
 39→  createdAt?: string;
 40→  updatedAt?: string;
 41→  workgroups?: WorkgroupSummary[];
 42→}
 43→
 44→const AssetManagement: React.FC = () => {
 45→  const [assets, setAssets] = useState<Asset[]>([]);
 46→  const [workgroups, setWorkgroups] = useState<Workgroup[]>([]);
 47→  const [loading, setLoading] = useState(true);
 48→  const [error, setError] = useState<string | null>(null);
 49→  const [showForm, setShowForm] = useState(false);
 50→  const [editingAsset, setEditingAsset] = useState<Asset | null>(null);
 51→  const [formData, setFormData] = useState<Asset & { workgroupIds?: number[] }>({
 52→    name: '',
 53→    type: '',
 54→    ip: '',
 55→    owner: '',
 56→    description: '',
 57→    criticality: undefined,
 58→    workgroupIds: []
 59→  });
 60→  const [showPortHistory, setShowPortHistory] = useState(false);
 61→  const [selectedAssetForPorts, setSelectedAssetForPorts] = useState<Asset | null>(null);
 62→  const [showVulnerabilities, setShowVulnerabilities] = useState(false);
 63→  const [selectedAssetForVulns, setSelectedAssetForVulns] = useState<Asset | null>(null);
 64→
 65→  // Filter states
 66→  const [nameFilter, setNameFilter] = useState<string>('');
 67→  const [ipFilter, setIpFilter] = useState<string>('');
 68→  const [ownerFilter, setOwnerFilter] = useState<string>('');
 69→  const [adDomainFilter, setAdDomainFilter] = useState<string>('');
 70→  const [workgroupFilter, setWorkgroupFilter] = useState<string>('');
 71→
 72→  // Bulk delete states (Feature 029 - User Story 1)
 73→  const [showBulkDeleteModal, setShowBulkDeleteModal] = useState(false);
 74→  const [isDeletingBulk, setIsDeletingBulk] = useState(false);
 75→  const [bulkDeleteSuccess, setBulkDeleteSuccess] = useState<string | null>(null);
 76→
 77→  // Export vulnerabilities state
 78→  const [exportLoading, setExportLoading] = useState(false);
 79→  const [exportProgress, setExportProgress] = useState<ExportJob | null>(null);
 80→  const [exportJobId, setExportJobId] = useState<string | null>(null);
 81→
 82→  // Owner candidates for select dropdown
 83→  const [ownerCandidates, setOwnerCandidates] = useState<OwnerCandidate[]>([]);
 84→  const canAssignOwner = isAdmin(getUser()?.roles) || isSecChampion(getUser()?.roles);
 85→
 86→  // Domain validation state (Feature 043 - User Story 2)
 87→  const [domainError, setDomainError] = useState<string | null>(null);
 88→
 89→  useEffect(() => {
 90→    fetchAssets();
 91→    if (isAdmin(getUser()?.roles)) {
 92→      fetchWorkgroups();
 93→    }
 94→    if (canAssignOwner) {
 95→      fetchOwnerCandidates();
 96→    }
 97→  }, []);
 98→
 99→  const fetchAssets = async () => {
100→    try {
101→      const response = await authenticatedGet('/api/assets');
102→      if (response.ok) {
103→        const data = await response.json();
104→        setAssets(data);
105→      } else {
106→        setError(`Failed to fetch assets: ${response.status}`);
107→      }
108→    } catch (err) {
109→      setError(err instanceof Error ? err.message : 'An error occurred');
110→    } finally {
111→      setLoading(false);
112→    }
113→  };
114→
115→  const fetchWorkgroups = async () => {
116→    try {
117→      const response = await authenticatedGet('/api/workgroups');
118→      if (response.ok) {
119→        const data: Workgroup[] = await response.json();
120→        setWorkgroups(data);
121→      } else if (response.status === 403) {
122→        // User doesn't have ADMIN role - workgroups filter not available
123→        console.info('Workgroups filter not available for non-admin users');
124→        setWorkgroups([]);
125→      } else {
126→        console.error('Failed to fetch workgroups, status:', response.status);
127→        setWorkgroups([]);
128→      }
129→    } catch (err) {
130→      console.error('Failed to fetch workgroups:', err);
131→      setWorkgroups([]);
132→    }
133→  };
134→
135→  const fetchOwnerCandidates = async () => {
136→    try {
137→      const response = await authenticatedGet('/api/assets/owner-candidates');
138→      if (response.ok) {
139→        const data: OwnerCandidate[] = await response.json();
140→        setOwnerCandidates(data);
141→      }
142→    } catch (err) {
143→      console.error('Failed to fetch owner candidates:', err);
144→    }
145→  };
146→
147→  /**
148→   * Validate Active Directory domain field
149→   * Feature 043: User Story 2 - Manual Domain Editing
150→   *
151→   * Validation rules:
152→   * - Pattern: alphanumeric, dots, and hyphens only
153→   * - Cannot start or end with a dot
154→   * - Max length 255 characters
155→   * - Optional field (empty is valid)
156→   */
157→  const validateDomain = (value: string): boolean => {
158→    if (!value || value.trim() === '') {
159→      setDomainError(null);
160→      return true; // Empty is valid (optional field)
161→    }
162→
163→    const trimmedValue = value.trim();
164→
165→    // Check length
166→    if (trimmedValue.length > 255) {
167→      setDomainError('Domain cannot exceed 255 characters');
168→      return false;
169→    }
170→
171→    // Check pattern: only alphanumeric, dots, and hyphens
172→    const regex = /^[a-zA-Z0-9.-]+$/;
173→    if (!regex.test(trimmedValue)) {
174→      setDomainError('Domain must contain only letters, numbers, dots, and hyphens');
175→      return false;
176→    }
177→
178→    // Cannot start with a dot
179→    if (trimmedValue.startsWith('.')) {
180→      setDomainError('Domain cannot start with a dot');
181→      return false;
182→    }
183→
184→    // Cannot end with a dot
185→    if (trimmedValue.endsWith('.')) {
186→      setDomainError('Domain cannot end with a dot');
187→      return false;
188→    }
189→
190→    // Cannot have consecutive dots
191→    if (trimmedValue.includes('..')) {
192→      setDomainError('Domain cannot contain consecutive dots');
193→      return false;
194→    }
195→
196→    // Valid
197→    setDomainError(null);
198→    return true;
199→  };
200→
201→  const handleSubmit = async (e: React.FormEvent) => {
202→    e.preventDefault();
203→
204→    // Validate domain before submission (Feature 043)
205→    if (formData.adDomain && !validateDomain(formData.adDomain)) {
206→      return; // Validation error is already set in state
207→    }
208→
209→    try {
210→      if (editingAsset) {
211→        await authenticatedPut(`/api/assets/${editingAsset.id}`, formData);
212→      } else {
213→        await authenticatedPost('/api/assets', formData);
214→      }
215→
216→      await fetchAssets();
217→      resetForm();
218→      setError(null);
219→    } catch (err) {
220→      setError(err instanceof Error ? err.message : 'An error occurred');
221→    }
222→  };
223→
224→  const handleEdit = (asset: Asset) => {
225→    console.log('Edit button clicked for asset:', asset.name, asset);
226→    setEditingAsset(asset);
227→    setFormData({
228→      ...asset,
229→      workgroupIds: asset.workgroups?.map(wg => wg.id) || []
230→    });
231→    setShowForm(true);
232→
233→    // Scroll to top to show the form
234→    setTimeout(() => {
235→      window.scrollTo({ top: 0, behavior: 'smooth' });
236→    }, 100);
237→  };
238→
239→  const handleDelete = async (id: number) => {
240→    if (!window.confirm('Are you sure you want to delete this asset? This will also delete all related vulnerabilities and exceptions.')) {
241→      return;
242→    }
243→
244→    try {
245→      const response = await authenticatedDelete(`/api/assets/${id}`);
246→
247→      if (!response.ok) {
248→        // Handle different error response formats
249→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
250→
251→        // Check for new DeletionErrorDto format (cascade deletion errors)
252→        if (errorData.errorType) {
253→          const errorMessage = `${errorData.cause}\n\nSuggested action: ${errorData.suggestedAction}`;
254→          throw new Error(errorMessage);
255→        }
256→
257→        // Handle old ErrorResponse format
258→        throw new Error(errorData.error || `Failed to delete asset: ${response.status}`);
259→      }
260→
261→      // Handle success - can be either old format (message) or new format (CascadeDeletionResultDto)
262→      const result = await response.json().catch(() => null);
263→
264→      if (result && result.deletedVulnerabilities !== undefined) {
265→        // New cascade deletion result format
266→        console.log(`Deleted asset ${result.assetId}: ${result.deletedVulnerabilities} vulnerabilities, ${result.deletedExceptions} exceptions, ${result.deletedRequests} requests`);
267→      }
268→
269→      await fetchAssets();
270→      setError(null);
271→    } catch (err) {
272→      setError(err instanceof Error ? err.message : 'An error occurred while deleting the asset');
273→    }
274→  };
275→
276→  /**
277→   * Handle bulk delete of all assets
278→   * Feature 029: User Story 1 - Bulk Delete Assets
279→   */
280→  const handleBulkDelete = async () => {
281→    setIsDeletingBulk(true);
282→    setError(null);
283→    setBulkDeleteSuccess(null);
284→
285→    try {
286→      const result: BulkDeleteResult = await bulkDeleteAssets();
287→
288→      // Show success message
289→      setBulkDeleteSuccess(result.message);
290→
291→      // Close modal
292→      setShowBulkDeleteModal(false);
293→
294→      // Refresh asset list
295→      await fetchAssets();
296→
297→      // Clear success message after 5 seconds
298→      setTimeout(() => setBulkDeleteSuccess(null), 5000);
299→
300→    } catch (err) {
301→      setError(err instanceof Error ? err.message : 'An error occurred during bulk delete');
302→      setShowBulkDeleteModal(false);
303→    } finally {
304→      setIsDeletingBulk(false);
305→    }
306→  };
307→
308→  /**
309→   * Handle export of all vulnerabilities to Excel
310→   * Feature: Vulnerability Export Performance Optimization - Background Job Pattern
311→   *
312→   * Uses background job pattern with progress tracking:
313→   * - Starts export job asynchronously
314→   * - Polls for progress (updates UI every 2 seconds)
315→   * - Downloads file when complete
316→   * - Supports cancellation
317→   */
318→  const handleExportVulnerabilities = async () => {
319→    try {
320→      setExportLoading(true);
321→      setExportProgress(null);
322→      setError(null);
323→
324→      // Use server-side export with progress tracking
325→      await exportVulnerabilitiesServerSide((job) => {
326→        setExportProgress(job);
327→        setExportJobId(job.jobId);
328→      });
329→
330→      // Show brief success message
331→      setBulkDeleteSuccess('Export completed successfully!');
332→      setTimeout(() => setBulkDeleteSuccess(null), 5000);
333→
334→    } catch (err) {
335→      setError(err instanceof Error ? err.message : 'Failed to export vulnerabilities');
336→    } finally {
337→      setExportLoading(false);
338→      setExportProgress(null);
339→      setExportJobId(null);
340→    }
341→  };
342→
343→  /**
344→   * Handle cancellation of running export
345→   */
346→  const handleCancelExport = async () => {
347→    if (!exportJobId) return;
348→
349→    try {
350→      await cancelExportJob(exportJobId);
351→      setExportLoading(false);
352→      setExportProgress(null);
353→      setExportJobId(null);
354→    } catch (err) {
355→      setError(err instanceof Error ? err.message : 'Failed to cancel export');
356→    }
357→  };
358→
359→  const resetForm = () => {
360→    setFormData({
361→      name: '',
362→      type: '',
363→      ip: '',
364→      owner: '',
365→      description: '',
366→      adDomain: '',
367→      criticality: undefined,
368→      workgroupIds: []
369→    });
370→    setEditingAsset(null);
371→    setShowForm(false);
372→    setDomainError(null); // Clear domain validation error (Feature 043)
373→  };
374→
375→  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
376→    const { name, value } = e.target;
377→    setFormData(prev => ({ ...prev, [name]: value }));
378→  };
379→
380→  const handleCriticalityChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
381→    const value = e.target.value;
382→    setFormData(prev => ({
383→      ...prev,
384→      criticality: value === '' ? undefined : (value as 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW' | 'NA')
385→    }));
386→  };
387→
388→  const handleWorkgroupChange = (e: React.ChangeEvent<HTMLInputElement>) => {
389→    const workgroupId = parseInt(e.target.value);
390→    const { checked } = e.target;
391→    setFormData(prev => {
392→      const newWorkgroupIds = checked
393→        ? [...(prev.workgroupIds || []), workgroupId]
394→        : (prev.workgroupIds || []).filter(id => id !== workgroupId);
395→      return { ...prev, workgroupIds: newWorkgroupIds };
396→    });
397→  };
398→
399→  const handleShowPorts = (asset: Asset) => {
400→    setSelectedAssetForPorts(asset);
401→    setShowPortHistory(true);
402→  };
403→
404→  const handleClosePortHistory = () => {
405→    setShowPortHistory(false);
406→    setSelectedAssetForPorts(null);
407→  };
408→
409→  const handleShowVulnerabilities = (asset: Asset) => {
410→    setSelectedAssetForVulns(asset);
411→    setShowVulnerabilities(true);
412→  };
413→
414→  const handleCloseVulnerabilities = () => {
415→    setShowVulnerabilities(false);
416→    setSelectedAssetForVulns(null);
417→  };
418→
419→  // Filter assets based on current filter values
420→  const getFilteredAssets = () => {
421→    return assets.filter(asset => {
422→      // Text filters use partial matching
423→      const nameMatch = !nameFilter || asset.name.toLowerCase().includes(nameFilter.toLowerCase());
424→      const ipMatch = !ipFilter || (asset.ip && asset.ip.toLowerCase().includes(ipFilter.toLowerCase()));
425→      // Dropdown filters use exact matching
426→      const ownerMatch = !ownerFilter || asset.owner === ownerFilter;
427→      const adDomainMatch = !adDomainFilter || asset.adDomain === adDomainFilter;
428→      const workgroupMatch = !workgroupFilter || (
429→        asset.workgroups && asset.workgroups.some(wg => wg.name === workgroupFilter)
430→      );
431→
432→      return nameMatch && ipMatch && ownerMatch && adDomainMatch && workgroupMatch;
433→    });
434→  };
435→
436→  if (loading) {
437→    return (
438→      <div className="d-flex justify-content-center">
439→        <div className="spinner-border" role="status">
440→          <span className="visually-hidden">Loading...</span>
441→        </div>
442→      </div>
443→    );
444→  }
445→
446→  if (error) {
447→    return (
448→      <div className="container-fluid p-4">
449→        <div className="alert alert-danger" role="alert">
450→          {error}
451→        </div>
452→      </div>
453→    );
454→  }
455→
456→  return (
457→    <div className="container-fluid p-4">
458→      <div className="row">
459→        <div className="col-12">
460→          <div className="d-flex justify-content-between align-items-center mb-4">
461→            <h2>Asset Management</h2>
462→            <div className="btn-group" role="group">
463→              <button
464→                type="button"
465→                className="btn btn-primary"
466→                onClick={() => {
467→                  if (showForm) {
468→                    resetForm();
469→                  } else {
470→                    setShowForm(true);
471→                  }
472→                }}
473→              >
474→                {showForm ? 'Cancel' : 'Add New Asset'}
475→              </button>
476→              {/* Export Vulnerabilities Button (ADMIN, VULN, SECCHAMPION roles) */}
477→              {hasVulnAccess() && (
478→                <>
479→                  <button
480→                    type="button"
481→                    className="btn btn-success"
482→                    onClick={handleExportVulnerabilities}
483→                    disabled={exportLoading}
484→                    title="Export all vulnerabilities to Excel"
485→                  >
486→                    {exportLoading ? (
487→                      <>
488→                        <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
489→                        {exportProgress
490→                          ? `${exportProgress.progressPercent}%`
491→                          : 'Starting...'}
492→                      </>
493→                    ) : (
494→                      <>
495→                        <i className="bi bi-download me-2"></i>
496→                        Export Vulns
497→                      </>
498→                    )}
499→                  </button>
500→                  {exportLoading && (
501→                    <button
502→                      type="button"
503→                      className="btn btn-outline-danger"
504→                      onClick={handleCancelExport}
505→                      title="Cancel export"
506→                    >
507→                      <i className="bi bi-x-circle"></i>
508→                    </button>
509→                  )}
510→                </>
511→              )}
512→              {/* Feature 029: Bulk Delete Button (ADMIN only, hidden when no assets) */}
513→              {isAdmin(getUser()?.roles) && getFilteredAssets().length > 0 && (
514→                <button
515→                  type="button"
516→                  className="btn btn-danger"
517→                  onClick={() => setShowBulkDeleteModal(true)}
518→                  disabled={isDeletingBulk}
519→                >
520→                  <i className="bi bi-trash3-fill me-2"></i>
521→                  Delete All Assets
522→                </button>
523→              )}
524→            </div>
525→          </div>
526→        </div>
527→      </div>
528→      {showForm && (
529→        <div className="row mb-4">
530→          <div className="col-12">
531→            <div className="card">
532→              <div className="card-body">
533→                <h5 className="card-title">{editingAsset ? 'Edit Asset' : 'Add New Asset'}</h5>
534→                <form onSubmit={handleSubmit}>
535→                  <div className="mb-3">
536→                    <label htmlFor="name" className="form-label">Name *</label>
537→                    <input
538→                      type="text"
539→                      className="form-control"
540→                      id="name"
541→                      name="name"
542→                      value={formData.name}
543→                      onChange={handleInputChange}
544→                      required
545→                    />
546→                  </div>
547→                  <div className="mb-3">
548→                    <label htmlFor="type" className="form-label">Type *</label>
549→                    <select
550→                      className="form-control"
551→                      id="type"
552→                      name="type"
553→                      value={formData.type}
554→                      onChange={handleInputChange}
555→                      required
556→                    >
557→                      <option value="">Select Type</option>
558→                      <option value="Server">Server</option>
559→                      <option value="Workstation">Workstation</option>
560→                      <option value="Network Device">Network Device</option>
561→                      <option value="Mobile Device">Mobile Device</option>
562→                      <option value="IoT Device">IoT Device</option>
563→                      <option value="Database">Database</option>
564→                      <option value="Application">Application</option>
565→                      <option value="Other">Other</option>
566→                    </select>
567→                  </div>
568→                  <div className="mb-3">
569→                    <label htmlFor="ip" className="form-label">IP Address</label>
570→                    <input
571→                      type="text"
572→                      className="form-control"
573→                      id="ip"
574→                      name="ip"
575→                      value={formData.ip}
576→                      onChange={handleInputChange}
577→                      placeholder="e.g., 192.168.1.100"
578→                    />
579→                  </div>
580→                  <div className="mb-3">
581→                    <label htmlFor="owner" className="form-label">Owner *</label>
582→                    {canAssignOwner && ownerCandidates.length > 0 ? (
583→                      <select
584→                        className="form-select"
585→                        id="owner"
586→                        name="owner"
587→                        value={formData.owner}
588→                        onChange={handleInputChange}
589→                        required
590→                      >
591→                        <option value="">Select Owner</option>
592→                        {/* Show current value if not in candidates list (legacy data) */}
593→                        {formData.owner && !ownerCandidates.some(c => c.value === formData.owner) && (
594→                          <option value={formData.owner} disabled>{formData.owner} (not in system)</option>
595→                        )}
596→                        {ownerCandidates.map(candidate => (
597→                          <option key={candidate.value} value={candidate.value}>{candidate.label}</option>
598→                        ))}
599→                      </select>
600→                    ) : (
601→                      <input
602→                        type="text"
603→                        className="form-control"
604→                        id="owner"
605→                        name="owner"
606→                        value={formData.owner}
607→                        onChange={handleInputChange}
608→                        placeholder="Person or team responsible"
609→                        required
610→                      />
611→                    )}
612→                  </div>
613→                  <div className="mb-3">
614→                    <label htmlFor="adDomain" className="form-label">
615→                      AD Domain <span className="text-muted">(optional)</span>
616→                    </label>
617→                    <input
618→                      type="text"
619→                      className={`form-control ${domainError ? 'is-invalid' : ''}`}
620→                      id="adDomain"
621→                      name="adDomain"
622→                      value={formData.adDomain || ''}
623→                      onChange={(e) => {
624→                        handleInputChange(e);
625→                        validateDomain(e.target.value);
626→                      }}
627→                      placeholder="e.g., CONTOSO, corp.example.com"
628→                      maxLength={255}
629→                    />
630→                    {domainError && (
631→                      <div className="invalid-feedback">{domainError}</div>
632→                    )}
633→                    <small className="form-text text-muted">
634→                      Active Directory domain (alphanumeric, dots, and hyphens only)
635→                    </small>
636→                  </div>
637→                  <div className="mb-3">
638→                    <label htmlFor="description" className="form-label">Description</label>
639→                    <textarea
640→                      className="form-control"
641→                      id="description"
642→                      name="description"
643→                      value={formData.description}
644→                      onChange={handleInputChange}
645→                      placeholder="Description of the asset"
646→                      rows={3}
647→                    />
648→                  </div>
649→                  <div className="mb-3">
650→                    <label htmlFor="criticality" className="form-label">Criticality</label>
651→                    <select
652→                      className="form-select"
653→                      id="criticality"
654→                      name="criticality"
655→                      value={formData.criticality || ''}
656→                      onChange={handleCriticalityChange}
657→                    >
658→                      <option value="">Inherit from workgroup</option>
659→                      <option value="CRITICAL">🔴 CRITICAL</option>
660→                      <option value="HIGH">🟠 HIGH</option>
661→                      <option value="MEDIUM">🔵 MEDIUM</option>
662→                      <option value="LOW">⚪ LOW</option>
663→                      <option value="NA">➖ N/A</option>
664→                    </select>
665→                    <small className="text-muted">
666→                      Leave as "Inherit from workgroup" to use the highest criticality from assigned workgroups (excluding N/A). Default is MEDIUM if no workgroups assigned or all are N/A.
667→                    </small>
668→                  </div>
669→                  <div className="mb-3">
