427→ */
428→export async function downloadExportFile(jobId: string): Promise<void> {
429→    const response = await authenticatedGet(`/api/vulnerabilities/export/${jobId}/download`);
430→
431→    if (!response.ok) {
432→        if (response.status === 400) {
433→            const errorData = await response.json().catch(() => ({ error: 'Export not ready' }));
434→            throw new Error(errorData.error || 'Export is not ready for download');
435→        }
436→        throw new Error(`Failed to download export: ${response.status}`);
437→    }
438→
439→    // Get the blob from response
440→    const blob = await response.blob();
441→
442→    // Extract filename from Content-Disposition header, fallback to default
443→    const contentDisposition = response.headers.get('Content-Disposition');
444→    const filenameMatch = contentDisposition?.match(/filename="?([^"]+)"?/);
445→    const filename = filenameMatch?.[1] || `vulnerabilities_export_${new Date().toISOString().split('T')[0]}.xlsx`;
446→
447→    // Trigger download
448→    const url = URL.createObjectURL(blob);
449→    const a = document.createElement('a');
450→    a.href = url;
451→    a.download = filename;
452→    document.body.appendChild(a);
453→    a.click();
454→    document.body.removeChild(a);
455→    URL.revokeObjectURL(url);
456→}
