462→ */
463→export async function cancelExportJob(jobId: string): Promise<void> {
464→    const response = await authenticatedDelete(`/api/vulnerabilities/export/${jobId}`);
465→
466→    if (!response.ok && response.status !== 204) {
467→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
468→        throw new Error(errorData.error || `Failed to cancel export: ${response.status}`);
469→    }
470→}
471→
472→/**
473→ * Reset stuck export jobs
474→ * Use this when exports get stuck in PENDING/PROCESSING status
475→ *
476→ * @returns Number of jobs reset
477→ */
478→export async function resetStuckExportJobs(): Promise<{ message: string; resetCount: number }> {
479→    const response = await authenticatedPost('/api/vulnerabilities/export/reset', null);
480→
481→    if (!response.ok) {
482→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
483→        throw new Error(errorData.error || `Failed to reset stuck exports: ${response.status}`);
484→    }
485→
486→    return await response.json();
487→}
488→
489→/**
490→ * Export vulnerabilities with progress tracking
491→ * Feature: Vulnerability Export Performance Optimization - Background Job Pattern
492→ *
493→ * This is the main function to use for exporting. It:
494→ * 1. Starts the export job
495→ * 2. Polls for progress (calls onProgress callback)
496→ * 3. Downloads the file when complete
497→ *
498→ * @param onProgress Optional callback for progress updates
499→ * @returns Promise that resolves when download completes
500→ */
501→export async function exportVulnerabilitiesServerSide(
502→    onProgress?: (job: ExportJob) => void
503→): Promise<void> {
504→    // Start the export job
505→    const startResponse = await startVulnerabilityExport();
506→    const jobId = startResponse.jobId;
507→
508→    // Poll for status
509→    const pollInterval = 2000; // 2 seconds
510→    const maxPolls = 300; // 10 minutes max
511→    let polls = 0;
512→
513→    while (polls < maxPolls) {
514→        const job = await getExportJobStatus(jobId);
515→
516→        // Call progress callback
517→        if (onProgress) {
518→            onProgress(job);
519→        }
520→
521→        // Check if done
522→        if (job.status === 'COMPLETED') {
523→            // Download the file
524→            await downloadExportFile(jobId);
525→            return;
526→        }
527→
528→        if (job.status === 'FAILED') {
529→            throw new Error(job.errorMessage || 'Export failed');
530→        }
531→
532→        if (job.status === 'CANCELLED') {
533→            throw new Error('Export was cancelled');
534→        }
535→
536→        if (job.status === 'EXPIRED') {
537→            throw new Error('Export file has expired');
538→        }
539→
540→        // Wait before next poll
541→        await new Promise(resolve => setTimeout(resolve, pollInterval));
542→        polls++;
543→    }
544→
545→    throw new Error('Export timed out. Please try again.');
546→}
